// ================================================================
// 筛选与 zkoner 业务相关的最新热点话题
// ================================================================

// 品牌关注的关键词权重
const KEYWORDS = {
  'AI': 3, 'artificial intelligence': 3, 'LLM': 3, 'GPT': 3,
  'large language model': 3, 'ChatGPT': 3, 'Claude': 3, 'DeepSeek': 3,
  'automation': 2, 'workflow': 2, 'agent': 2, 'n8n': 2,
  'SEO': 2, 'GEO': 3, 'generative engine': 3,
  'startup': 1, 'business': 1, 'enterprise': 1,
  'knowledge graph': 3, 'structured data': 3, 'schema.org': 3,
  'search': 1, 'ranking': 1, 'visibility': 2,
  'growth': 1, 'marketing': 1, 'content': 1,
  '创业': 2, '企业': 2, '数字化': 2, '自动化': 3, '人工智能': 3
};

const items = $input.all();
let scored = [];

for (const item of items) {
  const json = item.json;
  const title = (json.title || '').toLowerCase();
  const content = (json.content || json.contentSnippet || json.description || '').toLowerCase();
  const text = title + ' ' + content;

  let score = 0;
  let matchedKeywords = [];
  for (const [kw, weight] of Object.entries(KEYWORDS)) {
    if (text.includes(kw)) {
      score += weight;
      matchedKeywords.push(kw);
    }
  }

  scored.push({
    title: json.title || '(无标题)',
    link: json.link || '',
    contentSnippet: (json.contentSnippet || json.description || '').slice(0, 300),
    score: score,
    matchedKeywords: matchedKeywords.slice(0, 8),
    isoDate: json.isoDate || ''
  });
}

// 按分数排序 (高分优先)
scored.sort((a, b) => b.score - a.score);

// 取最高分热点 (得分>0 的最多取2条, 否则取最新1条保底)
let top = scored.filter(s => s.score > 0).slice(0, 2);
if (top.length === 0 && scored.length > 0) {
  top = [scored[0]];
  top[0].score = 0;
  top[0].matchedKeywords = [];
}

const primary = top[0] || null;
const runnerUp = top[1] || null;

return [{
  totalScanned: items.length,
  topic: primary,
  runnerUp: runnerUp
}];

